import UIKit

class Account {
    var balance: Double = 0.0
    
    func deposit(amount: Double) {
        balance += amount
    }
    
    func withdraw(amount: Double) {
        if balance >= amount {
            balance -= amount
        } else {
            print("Insufficient funds")
        }
    }
}

class TransactionProcessor {
    func process(transaction: (Double, String)) -> Bool {
        let (amount, type) = transaction
        if type == "deposit" {
            account.deposit(amount: amount)
        } else if type == "withdraw" {
            account.withdraw(amount: amount)
        } else {
            return false
        }
        return true
    }
    
    private var account = Account()
}

class ViewController: UIViewController {
    @IBOutlet weak var balanceLabel: UILabel!
    
    let transactionProcessor = TransactionProcessor()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        updateBalance()
    }
    
    @IBAction func depositButtonTapped(_ sender: UIButton) {
        if let amount = Double(depositTextField.text ?? "0") {
            processTransaction(amount: amount, type: "deposit")
        }
    }
    
    @IBAction func withdrawButtonTapped(_ sender: UIButton) {
        if let amount = Double(withdrawTextField.text ?? "0") {
            processTransaction(amount: amount, type: "withdraw")
        }
    }
    
    private func updateBalance() {
        balanceLabel.text = String(format: "$%.2f", transactionProcessor.account.balance)
    }
    
    private func processTransaction(amount: Double, type: String) {
        if transactionProcessor.process(transaction: (amount, type)) {
            updateBalance()
        } else {
            print("Invalid transaction")
        }
    }
}